    expect(b2).toEqual(b2);
    expect(attr1).toEqual(attr2);
  });

  it('non-document', () => {
    const a = new Delta().insert('Test');
    const b = new Delta().delete(4);
    expect(() => {
      a.diff(b);
    }).toThrow(new Error('diff() called on non-document'));
  });
});

